pub fn detect_nvidia_processes() -> Vec<GpuProcess> {
    let stdout = match run_with_timeout(
        "nvidia-smi",
        &[
            "--query-compute-apps=pid,name,used_memory",
            "--format=csv,noheader,nounits",
        ],
        NVIDIA_SMI_TIMEOUT,
    ) {
        Some(s) => s,
        None => return Vec::new(),
    };

    parse_nvidia_processes(&stdout)
}
